function loadEmbeddedQuestions() {
  if (!EMBEDDED_QUESTIONS_TEXT) return;
  loadQuestions(EMBEDDED_QUESTIONS_TEXT, "내장 문제은행");
}

async function readTextFile(file, encoding) {
  const buffer = await file.arrayBuffer();
  return decodeBuffer(buffer, encoding);
}

function decodeBuffer(buffer, encoding) {
  const encodings = encoding === "auto" ? ["utf-8", "euc-kr"] : [encoding];
  let bestText = "";
  let bestScore = -Infinity;

  for (const item of encodings) {
    try {
      const text = new TextDecoder(item).decode(buffer);
      const score = scoreDecodedText(text);
      if (score > bestScore) {
        bestScore = score;
        bestText = text;
      }
    } catch (error) {
      // Unsupported encodings are ignored so the next option can try.
    }
  }

  return bestText || new TextDecoder("utf-8").decode(buffer);
}

function scoreDecodedText(text) {
  const good = (text.match(/\[(문제번호|과목|문제|보기|정답|해설|키워드)\]/g) || []).length;
  const bad = (text.match(/[�]/g) || []).length;
  const mojibake = (text.match(/[臾댁뺣]/g) || []).length;
  return good * 20 - bad * 10 - mojibake;
}

function loadQuestions(text, sourceName) {
  const parsed = parseQuestions(text);
  state.questions = parsed;
  state.currentSet = [];
  state.gradedIds.clear();
  els.quizList.innerHTML = "";
  els.newSetBtn.disabled = parsed.length === 0;
  els.gradeBtn.disabled = true;
  els.retryWrongBtn.disabled = state.wrongQuestions.length === 0;

  if (parsed.length === 0) {
    setStatus(`${sourceName}에서 문제를 찾지 못했습니다. [문제번호], [문제], [정답] 표기가 있는지 확인해 주세요.`);
    return;
  }

  setStatus(`${sourceName}에서 ${parsed.length}문제를 불러왔습니다. 랜덤 5문제를 눌러 시작하세요.`);
}

function parseQuestions(text) {
  const normalized = text.replace(/\r\n?/g, "\n").replace(/\uFEFF/g, "");
  const starts = [...normalized.matchAll(/\[\s*(?:문제번호|問題番號|문제\s*번호|臾몄젣踰덊샇)\s*\]/g)];

  if (starts.length === 0) {
    return parseLooseQuestions(normalized);
  }

  return starts.map((match, index) => {
    const start = match.index;
    const end = starts[index + 1]?.index ?? normalized.length;
    return parseBlock(normalized.slice(start, end), index);
  }).filter(isUsableQuestion);
}

function parseLooseQuestions(text) {
  return text
    .split(/\n{2,}(?=\s*(?:\d{1,4}[.)]|문제\s*\d+|\[))/)
    .map(parseBlock)
    .filter(isUsableQuestion);
}

function parseBlock(block, index = 0) {
  const sections = {};
  const regex = /\[\s*([^\]\n]+)\s*\]/g;
  const matches = [...block.matchAll(regex)];

  if (matches.length > 0) {
    for (let i = 0; i < matches.length; i++) {
      const rawLabel = cleanText(matches[i][1]);
      const key = normalizeLabel(rawLabel);
      const valueStart = matches[i].index + matches[i][0].length;
      const valueEnd = matches[i + 1]?.index ?? block.length;
      const value = cleanText(block.slice(valueStart, valueEnd));
      if (!sections[key]) sections[key] = value;
      else sections[key] += "\n" + value;
    }
  }

  const fallbackNumber = block.match(/(?:문제\s*)?(\d{1,4})[.)]/)?.[1] || String(index + 1).padStart(3, "0");
  const choices = parseChoices(sections.choices || "");
  const answer = cleanText(sections.answer || guessAnswerFromBlock(block));

  return {
    id: sections.number || fallbackNumber,
    subject: sections.subject || "과목 미분류",
    question: sections.question || cleanText(block.split("[보기]")[0] || block),
    choices,
    answer,
    explanation: sections.explanation || "",
    keywords: sections.keywords || "",
    type: detectType(choices, answer)
  };
}

function normalizeLabel(label) {
  const compact = label.replace(/\s+/g, "");
  const map = [
    ["number", ["문제번호", "번호", "臾몄젣踰덊샇"]],
    ["subject", ["과목", "怨쇰ぉ"]],
    ["question", ["문제", "臾몄젣"]],
    ["choices", ["보기", "蹂닿린"]],
    ["answer", ["정답", "?뺣떟"]],
    ["explanation", ["해설", "?댁꽕"]],
    ["keywords", ["키워드", "?ㅼ썙"]]
  ];

  for (const [key, labels] of map) {
    if (labels.some((item) => compact.includes(item))) return key;
  }
  return compact;
}

function parseChoices(text) {
  const cleaned = cleanText(text);
  if (!cleaned) return [];

  const lines = cleaned.split("\n").map(cleanText).filter(Boolean);
  const choices = [];
  let current = null;
  const marker = /^\s*(?:([1-9][0-9]?)[.)]|([①②③④⑤⑥⑦⑧⑨⑩])|([A-Ja-j])[.)]|[-*ㆍ·]\s*|[?？]{1,2})\s*(.*)$/;
  const circled = "①②③④⑤⑥⑦⑧⑨⑩";

  for (const line of lines) {
    const found = line.match(marker);
    if (found) {
      if (current) choices.push(current);
      const number = found[1] || (found[2] ? String(circled.indexOf(found[2]) + 1) : "") || found[3] || "";
      current = {
        value: number || String(choices.length + 1),
        text: cleanText(found[4] || line.replace(/^[-*ㆍ·?？\s]+/, ""))
      };
    } else if (current) {
      current.text = cleanText(`${current.text}\n${line}`);
    } else {
      current = { value: String(choices.length + 1), text: line };
    }
  }

  if (current) choices.push(current);
  return choices.filter((choice) => choice.text);
}

function guessAnswerFromBlock(block) {
  const labels = ["정답", "답", "?뺣떟"];
  const matches = [...block.matchAll(/\[\s*([^\]\n]+)\s*\]/g)];
  const answerLabel = matches.find((match) => labels.some((label) => match[1].includes(label)));
  if (!answerLabel) return "";
  const currentIndex = matches.indexOf(answerLabel);
  const valueStart = answerLabel.index + answerLabel[0].length;
  const valueEnd = matches[currentIndex + 1]?.index ?? block.length;
  return block.slice(valueStart, valueEnd);
}

function detectType(choices, answer) {
  const normalizedAnswer = normalizeAnswer(answer);
  const choiceTexts = choices.map((choice) => normalizeAnswer(choice.text));
  const hasOnlyOx = choices.length > 0 && choiceTexts.every((text) => text === "O" || text === "X");

  if (hasOnlyOx || normalizedAnswer === "O" || normalizedAnswer === "X") return "ox";
  if (choices.length >= 2 && /^[1-9][0-9]?$|^[A-J]$/.test(normalizedAnswer)) return "choice";
  if (/\(\s*\d+\s*[-:]\s*[A-Z가-힣0-9]+\s*\)/i.test(answer) || /[1-9]\s*[-:]\s*[A-Z가-힣0-9]+/i.test(answer)) return "matching";
  if (choices.length >= 2) return "choice";
  return "text";
}

function startSet(questions) {
  questions.forEach((question) => delete question.lastCorrect);
  state.currentSet = questions;
  state.gradedIds.clear();
  renderQuiz(questions);
  renderExamAssessment(null);
  els.gradeBtn.disabled = questions.length === 0;
  setStatus(`${questions.length}문제를 출제했습니다.`);
}

function startWrongSet() {
  const wrongOnly = uniqueQuestions(state.wrongQuestions);
  if (wrongOnly.length === 0) {
    setStatus("아직 저장된 오답이 없습니다.");
    return;
  }
  startSet(randomPick(wrongOnly, 5));
  setStatus(`오답 ${Math.min(5, wrongOnly.length)}문제를 다시 출제했습니다.`);
}

function renderQuiz(questions) {
  els.quizList.innerHTML = "";

  questions.forEach((question, index) => {
    const card = els.template.content.firstElementChild.cloneNode(true);
    card.dataset.questionId = question.id;
    card.querySelector(".question-number").textContent = `문제 ${question.id || index + 1}`;
    card.querySelector(".subject").textContent = question.subject;
    card.querySelector(".question-text").textContent = question.question;
    card.querySelector(".explanation-text").textContent = question.explanation || "해설이 없습니다.";
    card.querySelector(".keyword-text").textContent = question.keywords ? `키워드: ${question.keywords}` : "";

    const choicesEl = card.querySelector(".choices");
    const answerBox = card.querySelector(".answer-box");

    if ((question.type === "choice" || question.type === "ox") && question.choices.length > 0) {
      question.choices.forEach((choice, choiceIndex) => {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "choice-btn";
        button.dataset.value = choice.value || String(choiceIndex + 1);
        button.textContent = `${choice.value || choiceIndex + 1}. ${choice.text}`;
        button.addEventListener("click", () => {
          choicesEl.querySelectorAll(".choice-btn").forEach((item) => item.classList.remove("selected"));
          button.classList.add("selected");
          card.dataset.userAnswer = button.dataset.value;
        });
        choicesEl.appendChild(button);
      });
    } else {
      const textarea = document.createElement("textarea");
      textarea.placeholder = question.type === "matching" ? "예: (1-B), (2-C), (3-A)" : "정답을 입력하세요";
      textarea.addEventListener("input", () => {
        card.dataset.userAnswer = textarea.value;
      });
      answerBox.appendChild(textarea);
    }

    els.quizList.appendChild(card);
  });
}

function gradeCurrentSet() {
  let newlySolved = 0;
  let newlyCorrect = 0;
  let newlyWrong = 0;

  state.currentSet.forEach((question) => {
    const card = els.quizList.querySelector(`[data-question-id="${cssEscape(question.id)}"]`);
    if (!card) return;

    const userAnswer = card.dataset.userAnswer || "";
    const correct = isCorrect(userAnswer, question);
    question.lastCorrect = correct;
    const result = card.querySelector(".result");
    result.className = `result ${correct ? "correct" : "wrong"}`;
    result.textContent = correct ? `${pickPraise()} 정답: ${question.answer}` : `괜찮아요. 이 문제는 다시 보면 바로 잡힙니다. 정답: ${question.answer}`;

    if (!state.gradedIds.has(question.id)) {
      state.gradedIds.add(question.id);
      newlySolved++;
      if (correct) newlyCorrect++;
      else {
        newlyWrong++;
        state.wrongQuestions.push(question);
      }
    }
  });

  state.stats.solved += newlySolved;
  state.stats.correct += newlyCorrect;
  state.stats.wrong += newlyWrong;
  state.wrongQuestions = uniqueQuestions(state.wrongQuestions);
  els.retryWrongBtn.disabled = state.wrongQuestions.length === 0;
  saveStats();
  saveWrongQuestions();
  renderStats();
  renderExamAssessment(buildAssessment(state.currentSet));
  setStatus(`채점 완료: ${newlyCorrect}개 정답, ${newlyWrong}개 오답`);
}

function exportResults() {
  const payload = {
    app: "멀티미디어콘텐츠제작전문가 필기 퀴즈",
    exportedAt: new Date().toISOString(),
    stats: state.stats,
    latestAssessment: buildAssessment(state.currentSet),
    wrongQuestions: uniqueQuestions(state.wrongQuestions).map((question) => ({
      id: question.id,
      subject: question.subject,
      question: question.question,
      answer: question.answer,
      explanation: question.explanation,
      keywords: question.keywords
    }))
  };
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `multimedia-quiz-result-${todayKey()}.json`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
  setStatus("결과 파일을 내보냈습니다. 이 JSON 파일을 Codex에 올리면 약점 분석을 할 수 있습니다.");
}

function buildAssessment(questions) {
  const graded = (questions || []).filter((question) => typeof question.lastCorrect === "boolean");
  const total = graded.length;
  const correct = graded.filter((question) => question.lastCorrect).length;
  const percent = total ? Math.round((correct / total) * 100) : 0;
  const subjects = {};

  graded.forEach((question) => {
    const subject = question.subject || "과목 미분류";
    if (!subjects[subject]) subjects[subject] = { subject, total: 0, correct: 0, percent: 0 };
    subjects[subject].total++;
    if (question.lastCorrect) subjects[subject].correct++;
  });

  Object.values(subjects).forEach((item) => {
    item.percent = item.total ? Math.round((item.correct / item.total) * 100) : 0;
  });

  const subjectList = Object.values(subjects);
  const hasSubjectFail = subjectList.some((item) => item.percent < 40);
  const averagePass = percent >= 60;

  return {
    total,
    correct,
    wrong: total - correct,
    percent,
    averagePass,
    subjectPass: !hasSubjectFail,
    pass: total > 0 && averagePass && !hasSubjectFail,
    subjects: subjectList
  };
}

function renderExamAssessment(assessment) {
  if (!assessment || assessment.total === 0) {
    els.examStatus.textContent = "아직 채점 전";
    els.examMessage.textContent = "채점하면 평균 60점, 과목별 40점 기준으로 모의 판정합니다.";
    els.examPercent.textContent = "0%";
    els.examMargin.textContent = "60%까지 60% 남음";
    els.examBar.style.width = "0%";
    els.subjectBreakdown.textContent = "과목별 판정 대기 중";
    return;
  }

  const margin = assessment.percent - 60;
  els.examPercent.textContent = `${assessment.percent}%`;
  els.examMargin.textContent = margin >= 0 ? `커트라인보다 ${margin}% 높음` : `60%까지 ${Math.abs(margin)}% 부족`;
  els.examBar.style.width = `${Math.min(100, assessment.percent)}%`;

  if (assessment.pass) {
    els.examStatus.textContent = "합격권입니다";
    els.examMessage.textContent = `현재 세트 ${assessment.total}문제 기준 ${assessment.correct}개 정답. 평균 커트라인을 넘겼고 과락 위험도 없습니다. 좋아요, 꽤 든든합니다.`;
  } else if (!assessment.averagePass) {
    els.examStatus.textContent = "평균 점수 보강 필요";
    els.examMessage.textContent = `현재 세트 기준 ${assessment.percent}%입니다. 실제 필기 평균 합격선 60%까지 조금 더 끌어올리면 됩니다.`;
  } else {
    els.examStatus.textContent = "과락 위험 과목 확인";
    els.examMessage.textContent = "평균은 괜찮지만 한 과목이 40% 아래라면 실제 시험 기준으로는 위험합니다.";
  }

  els.subjectBreakdown.innerHTML = "";
  assessment.subjects.forEach((item) => {
    const pill = document.createElement("span");
    pill.className = `subject-pill ${item.percent >= 40 ? "pass" : "fail"}`;
    pill.textContent = `${item.subject}: ${item.percent}% (${item.correct}/${item.total})`;
    els.subjectBreakdown.appendChild(pill);
  });
}

function isCorrect(userAnswer, question) {
  const expected = normalizeAnswer(question.answer);
  const actual = normalizeAnswer(userAnswer);
  if (!expected || !actual) return false;

  if (question.type === "choice" || question.type === "ox") {
    const matchedChoice = question.choices.find((choice) => normalizeAnswer(choice.value) === actual);
    const actualText = matchedChoice ? normalizeAnswer(matchedChoice.text) : actual;
    return expected === actual || expected === actualText;
  }

  if (question.type === "matching") {
    return normalizeMatching(expected) === normalizeMatching(actual);
  }

  return expected === actual || expected.includes(actual) || actual.includes(expected);
}

function normalizeAnswer(value) {
  return String(value || "")
    .trim()
    .replace(/[①]/g, "1")
    .replace(/[②]/g, "2")
    .replace(/[③]/g, "3")
    .replace(/[④]/g, "4")
    .replace(/[⑤]/g, "5")
    .replace(/[０-９]/g, (char) => String.fromCharCode(char.charCodeAt(0) - 65248))
    .replace(/[×x]/g, "X")
    .replace(/[○Oo]/g, "O")
    .replace(/\s+/g, "")
    .replace(/[.,，、]/g, "")
    .toUpperCase();
}

function normalizeMatching(value) {
  const pairs = String(value).match(/[0-9A-Z가-힣]+\s*[-:]\s*[0-9A-Z가-힣]+/gi);
  if (!pairs) return normalizeAnswer(value);
  return pairs
    .map((pair) => pair.replace(/\s+/g, "").replace(":", "-").toUpperCase())
    .sort()
    .join(",");
}

function randomPick(items, count) {
  return [...items]
    .sort(() => Math.random() - 0.5)
    .slice(0, Math.min(count, items.length));
}

function pickPraise() {
  return PRAISE_MESSAGES[Math.floor(Math.random() * PRAISE_MESSAGES.length)];
}

function uniqueQuestions(questions) {
  const map = new Map();
  questions.forEach((question) => map.set(String(question.id), question));
  return [...map.values()];
}

function isUsableQuestion(question) {
  return question && question.question && question.answer;
}

function cleanText(text) {
  return String(text || "")
    .replace(/\r\n?/g, "\n")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function setStatus(message) {
  els.statusBox.textContent = message;
}

function todayKey() {
  const date = new Date();
  return `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`;
}

function loadStats() {
  try {
    const saved = JSON.parse(localStorage.getItem("multimediaQuizStats") || "null");
    if (saved && saved.date === todayKey()) state.stats = saved;
  } catch (error) {
    saveStats();
  }
}

function loadWrongQuestions() {
  try {
    const saved = JSON.parse(localStorage.getItem("multimediaQuizWrongQuestions") || "[]");
    if (Array.isArray(saved)) state.wrongQuestions = uniqueQuestions(saved);
  } catch (error) {
    state.wrongQuestions = [];
  }
}

function saveStats() {
  localStorage.setItem("multimediaQuizStats", JSON.stringify(state.stats));
}

function saveWrongQuestions() {
  localStorage.setItem("multimediaQuizWrongQuestions", JSON.stringify(uniqueQuestions(state.wrongQuestions)));
}

function renderStats() {
  els.todaySolved.textContent = state.stats.solved;
  els.todayCorrect.textContent = state.stats.correct;
  els.todayWrong.textContent = state.stats.wrong;
}

function cssEscape(value) {
  if (window.CSS && CSS.escape) return CSS.escape(String(value));
  return String(value).replace(/"/g, '\\"');
}

function registerServiceWorker() {
  if (!("serviceWorker" in navigator)) return;
  window.addEventListener("load", () => {
    navigator.serviceWorker.register("sw.js").catch(() => {
      setStatus("서비스 워커 등록이 막혔습니다. 배포된 HTTPS 주소에서는 오프라인 설치가 활성화됩니다.");
    });
  });
}


